// Node 2 — Preprocess
// Detects the uploaded file type, extracts/normalizes report text, runs the
// PHI redaction pass, and builds the Gemini triage request body.
//
// OCR note (Assumption A6): the privacy-preserving default in the spec is local
// Tesseract. Inside an n8n Code node there is no Tesseract binding, so this build
// uses the spec's documented alternative — Gemini-vision OCR during triage — by
// passing the image/PDF bytes inline to the triage call. To use local Tesseract
// instead, front this workflow with the Execute Command variant described in the
// README (docs/README section "OCR modes") so image bytes never leave the host.

const TRIAGE_PROMPT = `You are a medical triage router. Given a radiology report (and optionally its image),
return STRICT JSON only:
{
  "report_type": "<e.g. chest x-ray | skeletal/fracture | dental | abdominal | spine | other>",
  "specialty_1": "<specialty best suited to review this>",
  "specialty_2": "<a DIFFERENT relevant specialty>",
  "specialty_3": "<a THIRD, distinct relevant specialty>",
  "patient_context": "<echo any age/sex/history you can extract, else empty string>",
  "report_text_normalized": "<the cleaned plain-text report>"
}
If an image or scanned document is attached instead of plain text, transcribe (OCR) its
text faithfully into "report_text_normalized" before classifying.
Pick three DISTINCT specialties that would give genuinely different perspectives.
No markdown, no commentary — JSON only.`;

// Redaction pass — strips obvious identifiers BEFORE anything flows downstream
// or is logged (spec sections 3.5 / 6). Heuristic, not a certified de-identifier:
// all input data must already be de-identified per the mandatory safety rules.
function redactPHI(text) {
  if (!text) return text;
  let t = String(text);
  const rules = [
    [/\b(patient(?:\s+name)?|name|pt\.?)\s*[:\-]\s*[A-Z][A-Za-z'\-]+(?:[ ,]+[A-Z][A-Za-z'\-]+)*/g, '$1: [REDACTED]'],
    [/\b(dob|date\s+of\s+birth|birth\s*date)\s*[:\-]?\s*\d{1,4}[\/\-.]\d{1,2}[\/\-.]\d{1,4}/gi, '$1: [REDACTED]'],
    [/\b(mrn|medical\s+record\s+(?:no\.?|number|#)|record\s*#)\s*[:\-]?\s*[A-Za-z0-9\-]+/gi, '$1: [REDACTED]'],
    [/\b(accession\s*(?:no\.?|number|#)?)\s*[:\-]\s*[A-Za-z0-9\-]+/gi, '$1: [REDACTED]'],
    [/\b(ssn|social\s+security(?:\s+number)?)\s*[:\-]?\s*\d{3}-?\d{2}-?\d{4}/gi, '$1: [REDACTED]'],
    [/\b\d{3}[\-. ]\d{3}[\-. ]\d{4}\b/g, '[REDACTED-PHONE]'],
    [/\b[\w.+-]+@[\w-]+\.[\w.-]+\b/g, '[REDACTED-EMAIL]'],
  ];
  for (const [re, rep] of rules) t = t.replace(re, rep);
  return t;
}

const item = items[0];
const j = item.json || {};

// The Form Trigger exposes the uploaded file under a binary key named after the
// form field; scan keys so a renamed field does not break intake.
const binKeys = Object.keys(item.binary || {});
const bin = binKeys.length ? item.binary[binKeys[0]] : null;
if (!bin) {
  throw new Error('No file was uploaded. The intake form requires a report file (.txt, .png, .jpg, .pdf).');
}

const mime = (bin.mimeType || '').toLowerCase();
const fileName = (bin.fileName || '').toLowerCase();

let report_text = '';
let inline_b64 = null;   // image or PDF bytes forwarded ONLY to Gemini triage/specialist
let inline_mime = null;
let report_type_hint = '';

// Resolve the real bytes via n8n's binary helper. `bin.data` is only the raw
// base64 in the default in-memory mode; in filesystem/S3 modes it is a
// reference, so decoding it directly yields garbage. getBinaryDataBuffer
// returns the actual buffer in every mode.
let fileBuffer;
try {
  fileBuffer = await this.helpers.getBinaryDataBuffer(0, binKeys[0]);
} catch (e) {
  // Fallback for contexts where the helper is unavailable (e.g. offline tests):
  // treat bin.data as base64 only if it looks like base64.
  fileBuffer = Buffer.from(bin.data || '', 'base64');
}

if (mime.startsWith('text/') || fileName.endsWith('.txt')) {
  report_text = fileBuffer.toString('utf8');
} else if (mime.startsWith('image/') || mime === 'application/pdf' || /\.(png|jpe?g|pdf)$/.test(fileName)) {
  inline_b64 = fileBuffer.toString('base64');
  inline_mime = mime || (fileName.endsWith('.pdf') ? 'application/pdf' : 'image/png');
} else {
  throw new Error(`Unsupported file type "${mime || fileName}". Accepted: text/plain, image/png, image/jpeg, application/pdf.`);
}

// Only de-identified text flows downstream.
report_text = redactPHI(report_text);

const patient_context = [
  j.age ? `age: ${j.age}` : null,
  j.sex ? `sex: ${j.sex}` : null,
  j.history ? `history: ${redactPHI(j.history)}` : null,
].filter(Boolean).join('; ');

// Cheap type hint used only as a fallback if triage output cannot be parsed.
const hintSource = (report_text + ' ' + fileName).toLowerCase();
if (/chest|lung|cardiomediastin|pleural/.test(hintSource)) report_type_hint = 'chest x-ray';
else if (/fracture|femur|tibia|radius|humerus|bone/.test(hintSource)) report_type_hint = 'skeletal/fracture';
else if (/dental|panoramic|molar|mandib/.test(hintSource)) report_type_hint = 'dental';
else if (/abdom|bowel|kub/.test(hintSource)) report_type_hint = 'abdominal';
else if (/spine|vertebr|lumbar|cervical/.test(hintSource)) report_type_hint = 'spine';
else report_type_hint = 'other';

// Build the Gemini triage request (Section 2.4.1 / Node 3).
const parts = [];
const userText = [
  patient_context ? `PATIENT CONTEXT: ${patient_context}` : null,
  report_text ? `REPORT TEXT:\n"""\n${report_text}\n"""` : 'REPORT TEXT: (none — see attached scan; transcribe it)',
].filter(Boolean).join('\n\n');
parts.push({ text: userText });
if (inline_b64) parts.push({ inlineData: { mimeType: inline_mime, data: inline_b64 } });

const triage_request_body = {
  systemInstruction: { parts: [{ text: TRIAGE_PROMPT }] },
  contents: [{ role: 'user', parts }],
  generationConfig: { temperature: 0.2, responseMimeType: 'application/json' },
};

return [{
  json: {
    report_text,
    patient_context,
    report_type_hint,
    image_b64: inline_mime && inline_mime.startsWith('image/') ? inline_b64 : null,
    image_mime: inline_mime && inline_mime.startsWith('image/') ? inline_mime : null,
    triage_request_body,
    __t_start: Date.now(),
  },
}];

// Node 4 — Parse Triage
// Validates the triage JSON; on failure falls back to a default specialty triad
// for the detected report_type_hint (the HTTP node already retried once).

const pre = $('Preprocess').first().json;

const DEFAULT_TRIADS = {
  'chest x-ray': ['pulmonologist', 'thoracic radiologist', 'cardiothoracic surgeon'],
  'skeletal/fracture': ['orthopedic surgeon', 'musculoskeletal radiologist', 'emergency physician'],
  'dental': ['oral & maxillofacial radiologist', 'endodontist', 'oral surgeon'],
  'abdominal': ['abdominal radiologist', 'gastroenterologist', 'general surgeon'],
  'spine': ['neuroradiologist', 'spine surgeon', 'physiatrist'],
  'other': ['diagnostic radiologist', 'internal medicine physician', 'emergency physician'],
};

function extractJson(raw) {
  if (!raw) return null;
  let s = String(raw).trim().replace(/^```(?:json)?\s*/i, '').replace(/```\s*$/, '');
  const start = s.indexOf('{');
  const end = s.lastIndexOf('}');
  if (start === -1 || end <= start) return null;
  try { return JSON.parse(s.slice(start, end + 1)); } catch (e) { return null; }
}

const rawText = $json.candidates?.[0]?.content?.parts?.map(p => p.text || '').join('') ?? '';
let t = extractJson(rawText);

let triage_fallback_used = false;
const valid = t && typeof t === 'object'
  && typeof t.report_type === 'string'
  && [t.specialty_1, t.specialty_2, t.specialty_3].every(s => typeof s === 'string' && s.trim());

if (!valid) {
  triage_fallback_used = true;
  const triad = DEFAULT_TRIADS[pre.report_type_hint] || DEFAULT_TRIADS.other;
  t = {
    report_type: pre.report_type_hint || 'other',
    specialty_1: triad[0], specialty_2: triad[1], specialty_3: triad[2],
    patient_context: pre.patient_context,
    report_text_normalized: pre.report_text,
  };
}

// Enforce three DISTINCT specialties; backfill duplicates from the default triad.
const triad = DEFAULT_TRIADS[t.report_type?.toLowerCase?.()] || DEFAULT_TRIADS[pre.report_type_hint] || DEFAULT_TRIADS.other;
const seen = new Set();
const specs = [t.specialty_1, t.specialty_2, t.specialty_3].map(s => String(s || '').trim());
for (let i = 0; i < 3; i++) {
  const key = specs[i].toLowerCase();
  if (!specs[i] || seen.has(key)) {
    specs[i] = triad.find(d => !seen.has(d.toLowerCase())) || triad[i];
  }
  seen.add(specs[i].toLowerCase());
}

const report_text = (t.report_text_normalized && String(t.report_text_normalized).trim())
  ? String(t.report_text_normalized).trim()
  : pre.report_text;

if (!report_text) {
  throw new Error('No report text could be extracted from the upload (empty file and OCR produced nothing).');
}

return [{
  json: {
    report_type: t.report_type || 'other',
    specialty_1: specs[0],
    specialty_2: specs[1],
    specialty_3: specs[2],
    patient_context: t.patient_context || pre.patient_context || '',
    report_text,
    image_b64: pre.image_b64,
    image_mime: pre.image_mime,
    triage_fallback_used,
    __t_start: pre.__t_start,
    __t_triage_ms: Date.now() - pre.__t_start,
  },
}];

// Node 5 — Fan-out Critiques (Assumption A7: true concurrency via Promise.all)
// Fires Gemini + Ollama + DeepSeek specialists concurrently, validates each
// response against the SpecialistCritique schema, retries once with a stricter
// JSON reminder on malformed output, and never lets one backend stall the run
// (per-call timeout 30 s, hard branch ceiling 35 s).
//
// Credentials: n8n Code nodes cannot read the encrypted Credentials store, so
// keys come from process environment variables set for the n8n service
// (GEMINI_API_KEY, DEEPSEEK_API_KEY, OLLAMA_BASE_URL). The HTTP Request nodes in
// this workflow (triage, synthesis) DO use the Credentials store. See README
// "Credentials & environment".

const t = $json;

// Ollama (local) is much slower than the cloud backends, so it gets its own,
// longer per-call budget and the whole fan-out ceiling is sized to match.
const CALL_TIMEOUT_MS = 60000;                                   // gemini / deepseek
const OLLAMA_TIMEOUT_MS = Number($env.OLLAMA_TIMEOUT_MS || 115000);
const HARD_CEILING_MS = Number($env.XRAY_FANOUT_CEILING_MS || 120000);

// When DeepSeek is unavailable (e.g. no account balance -> HTTP 402), route the
// third specialist to Gemini instead. Matches the local runner's --no-deepseek.
const NO_DEEPSEEK = ['1', 'true', 'yes'].includes(String($env.XRAY_NO_DEEPSEEK || '').toLowerCase());

const GEMINI_MODEL = $env.GEMINI_SPECIALIST_MODEL || 'gemini-3.5-flash';
const OLLAMA_MODEL = $env.OLLAMA_MODEL || 'llama3.1:8b';
const DEEPSEEK_MODEL = $env.DEEPSEEK_SPECIALIST_MODEL || 'deepseek-v4-flash';
const OLLAMA_BASE = ($env.OLLAMA_BASE_URL || 'http://127.0.0.1:11434').replace(/\/+$/, '');

// ---------------------------------------------------------------- prompts ---
const SCHEMA_FIELDS_HELP = `The JSON object MUST have exactly these fields:
{
  "specialty_role": string,
  "key_observations": string[],            // findings salient to your specialty, grounded in the source
  "areas_of_concern": string[],            // ambiguous findings, missing views, absent priors, red flags
  "differential_considerations": string[], // plausible diagnoses, most-to-least likely
  "confidence_level": { "level": "low"|"medium"|"high", "rationale": string },
  "disagreements_with_original_report": string[], // empty array if none
  "recommended_next_steps": string[]
}`;

function specialistSystemPrompt(job) {
  return `You are a board-certified ${job.specialty} reviewing a radiology report as a second-opinion
consultant. You are one of three independent specialists; you cannot see the others' opinions.

Your job is to critique the report below from the specific viewpoint of a ${job.specialty} —
not to re-write it. Focus on what your specialty would notice, question, or add.

INPUT YOU ARE GIVEN
- Report type: ${t.report_type}
- Patient context (may be partial or empty): ${t.patient_context || '(none provided)'}
- Radiology report text:
  """
  ${t.report_text}
  """
${job.withImage ? '- An X-ray image is also attached for your direct inspection.' : ''}

RULES
1. Base every observation ONLY on the report text (and image, if attached). Do NOT invent findings,
   measurements, or history that are not present or reasonably inferable from the input.
2. If the report is text-only and you are a text model, analyze the WORDS of the report — do not
   claim to have seen the image.
3. If something important is missing from the report (e.g. no lateral view, no prior comparison),
   say so under areas_of_concern.
4. State your confidence honestly and explain it.
5. Output STRICT JSON matching the schema. No markdown, no commentary outside the JSON.

${SCHEMA_FIELDS_HELP}

Return ONLY the JSON object described in the schema.`;
}

function userPayload(job) {
  return JSON.stringify({
    specialty_role: job.specialty,
    report_type: t.report_type,
    patient_context: t.patient_context || '',
    report_text: t.report_text,
    image_provided: !!job.withImage,
  });
}

const STRICT_REMINDER = 'REMINDER: Your previous output was not valid. Return ONLY one valid JSON object exactly matching the schema — no markdown fences, no prose, no trailing text.';

// ------------------------------------------------------- schema validation ---
// Hand-rolled validator (external modules like ajv are not importable in a
// stock n8n Code node). Mirrors schemas/specialist-critique.schema.json.
function validateCritique(c) {
  if (!c || typeof c !== 'object' || Array.isArray(c)) return false;
  if (typeof c.specialty_role !== 'string' || !c.specialty_role.trim()) return false;
  const strArr = k => Array.isArray(c[k]) && c[k].every(x => typeof x === 'string');
  for (const k of ['key_observations', 'areas_of_concern', 'differential_considerations',
                   'disagreements_with_original_report', 'recommended_next_steps']) {
    if (!strArr(k)) return false;
  }
  const cl = c.confidence_level;
  if (!cl || typeof cl !== 'object' || Array.isArray(cl)) return false;
  if (!['low', 'medium', 'high'].includes(cl.level)) return false;
  if (typeof cl.rationale !== 'string') return false;
  return true;
}

function extractJson(raw) {
  if (raw == null) return null;
  let s = String(raw).trim().replace(/^```(?:json)?\s*/i, '').replace(/```\s*$/, '');
  const start = s.indexOf('{');
  const end = s.lastIndexOf('}');
  if (start === -1 || end <= start) return null;
  try { return JSON.parse(s.slice(start, end + 1)); } catch (e) { return null; }
}

// -------------------------------------------------------- request builders ---
// Gemini-flavored response schema (enforced server-side, Section 2.4.1).
const GEMINI_RESPONSE_SCHEMA = {
  type: 'object',
  properties: {
    specialty_role: { type: 'string' },
    key_observations: { type: 'array', items: { type: 'string' } },
    areas_of_concern: { type: 'array', items: { type: 'string' } },
    differential_considerations: { type: 'array', items: { type: 'string' } },
    confidence_level: {
      type: 'object',
      properties: {
        level: { type: 'string', enum: ['low', 'medium', 'high'] },
        rationale: { type: 'string' },
      },
      required: ['level', 'rationale'],
    },
    disagreements_with_original_report: { type: 'array', items: { type: 'string' } },
    recommended_next_steps: { type: 'array', items: { type: 'string' } },
  },
  required: ['specialty_role', 'key_observations', 'areas_of_concern', 'differential_considerations',
             'confidence_level', 'disagreements_with_original_report', 'recommended_next_steps'],
};

function buildRequest(job, strict) {
  const sys = specialistSystemPrompt(job) + (strict ? '\n\n' + STRICT_REMINDER : '');
  if (job.backend === 'gemini') {
    if (!$env.GEMINI_API_KEY) throw new Error('GEMINI_API_KEY env var is not set for the n8n process');
    const parts = [{ text: userPayload(job) }];
    if (job.withImage) parts.push({ inlineData: { mimeType: t.image_mime || 'image/png', data: t.image_b64 } });
    return {
      method: 'POST',
      url: `https://generativelanguage.googleapis.com/v1beta/models/${GEMINI_MODEL}:generateContent`,
      headers: { 'x-goog-api-key': $env.GEMINI_API_KEY, 'Content-Type': 'application/json' },
      body: {
        systemInstruction: { parts: [{ text: sys }] },
        contents: [{ role: 'user', parts }],
        generationConfig: {
          temperature: 0.2,
          responseMimeType: 'application/json',
          responseSchema: GEMINI_RESPONSE_SCHEMA,
        },
      },
      json: true,
      timeout: CALL_TIMEOUT_MS,
    };
  }
  if (job.backend === 'ollama') {
    return {
      method: 'POST',
      url: `${OLLAMA_BASE}/api/chat`,
      headers: { 'Content-Type': 'application/json' },
      body: {
        model: OLLAMA_MODEL,
        messages: [
          { role: 'system', content: sys },
          { role: 'user', content: userPayload(job) },
        ],
        format: 'json',
        stream: false,
        options: { temperature: 0.2 },
      },
      json: true,
      timeout: OLLAMA_TIMEOUT_MS,
    };
  }
  if (job.backend === 'deepseek') {
    if (!$env.DEEPSEEK_API_KEY) throw new Error('DEEPSEEK_API_KEY env var is not set for the n8n process');
    return {
      method: 'POST',
      url: 'https://api.deepseek.com/chat/completions',
      headers: { Authorization: `Bearer ${$env.DEEPSEEK_API_KEY}`, 'Content-Type': 'application/json' },
      body: {
        model: DEEPSEEK_MODEL,
        messages: [
          { role: 'system', content: sys },
          { role: 'user', content: userPayload(job) },
        ],
        response_format: { type: 'json_object' },
        temperature: 0.2,
        thinking: { type: 'disabled' },
      },
      json: true,
      timeout: CALL_TIMEOUT_MS,
    };
  }
  throw new Error(`Unknown backend: ${job.backend}`);
}

function extractText(backend, raw) {
  if (backend === 'gemini') return raw?.candidates?.[0]?.content?.parts?.map(p => p.text || '').join('') ?? '';
  if (backend === 'ollama') return raw?.message?.content ?? '';
  if (backend === 'deepseek') return raw?.choices?.[0]?.message?.content ?? '';
  return '';
}

// ------------------------------------------------------------------ runner ---
const jobs = [
  { backend: 'gemini', model: GEMINI_MODEL, specialty: t.specialty_1, withImage: !!t.image_b64 },
  { backend: 'ollama', model: OLLAMA_MODEL, specialty: t.specialty_2, withImage: false },
  NO_DEEPSEEK
    ? { backend: 'gemini', model: GEMINI_MODEL, specialty: t.specialty_3, withImage: false }
    : { backend: 'deepseek', model: DEEPSEEK_MODEL, specialty: t.specialty_3, withImage: false },
];

// Cloud backends occasionally return a transient 5xx/429 (e.g. Gemini 503
// "overloaded"). Retry such calls once after a short backoff before giving up.
function isTransient(e) {
  const s = e && (e.statusCode || e.httpCode || e.status);
  if (s && [429, 500, 502, 503, 504].includes(Number(s))) return true;
  return /\b(429|500|502|503|504)\b|overloaded|ETIMEDOUT|ECONNRESET|socket hang up/i.test(String(e && e.message ? e.message : e));
}
async function httpWithTransientRetry(req) {
  try {
    return await this.helpers.httpRequest(req);
  } catch (e) {
    if (!isTransient(e)) throw e;
    await new Promise(r => setTimeout(r, 1500));
    return await this.helpers.httpRequest(req);
  }
}

const callAgent = async (job) => {
  const started = Date.now();
  try {
    const raw = await httpWithTransientRetry.call(this, buildRequest(job, false));
    let critique = extractJson(extractText(job.backend, raw));
    let rawText = extractText(job.backend, raw);
    if (!validateCritique(critique)) {
      // One retry with the stricter "return ONLY valid JSON" reminder (Section 2.6).
      const raw2 = await httpWithTransientRetry.call(this, buildRequest(job, true));
      rawText = extractText(job.backend, raw2);
      critique = extractJson(rawText);
    }
    if (!validateCritique(critique)) {
      return {
        backend: job.backend, model: job.model, specialty: job.specialty,
        parse_failed: true, raw_text_fallback: String(rawText).slice(0, 4000),
        ms: Date.now() - started,
      };
    }
    critique.__backend = job.backend;
    critique.__model = job.model;
    critique.__image_provided = !!job.withImage;
    critique.__ms = Date.now() - started;
    // Keep the persona honest even if the model paraphrased it.
    critique.specialty_role = critique.specialty_role || job.specialty;
    return critique;
  } catch (e) {
    return {
      backend: job.backend, model: job.model, specialty: job.specialty,
      failed: true, error: String(e && e.message ? e.message : e).slice(0, 500),
      ms: Date.now() - started,
    };
  }
};

// Hard ceiling: the fan-out resolves when all three settle OR at HARD_CEILING_MS,
// whichever comes first, so one hung backend cannot stall the pipeline.
const withCeiling = (p, job) => Promise.race([
  p,
  new Promise(res => setTimeout(() => res({
    backend: job.backend, model: job.model, specialty: job.specialty,
    failed: true, error: `branch ceiling ${HARD_CEILING_MS} ms exceeded`, ms: HARD_CEILING_MS,
  }), HARD_CEILING_MS)),
]);

const results = await Promise.all(jobs.map(j => withCeiling(callAgent(j), j)));

const critiques = results.filter(r => !r.failed && !r.parse_failed);
const failures = results.filter(r => r.failed || r.parse_failed);

return [{
  json: {
    critiques,
    failures,
    original: {
      report_text: t.report_text,
      report_type: t.report_type,
      patient_context: t.patient_context,
      image_provided: !!t.image_b64,
      triage_fallback_used: !!t.triage_fallback_used,
      specialties: [t.specialty_1, t.specialty_2, t.specialty_3],
    },
    // Image bytes are intentionally dropped here — nothing downstream needs
    // them and they must not be persisted (Section 4 / 6).
    __t_start: t.__t_start,
    __t_triage_ms: t.__t_triage_ms,
    __t_fanout_ms: Math.max(...results.map(r => r.ms || r.__ms || 0)),
    __agent_timings: results.map(r => ({
      backend: r.backend || r.__backend, model: r.model || r.__model,
      ms: r.ms || r.__ms, failed: !!r.failed, parse_failed: !!r.parse_failed,
    })),
  },
}];

// Node 6 — Merge Guard
// Assembles the available critiques, computes missing_critiques, and builds the
// complete DeepSeek synthesis request body. If zero critiques survived, sets
// has_critiques=false so the IF node short-circuits to the error report —
// never a fabricated diagnosis (Section 2.6).

const DISCLAIMER = "──────────────────────────────────────────────────────────────────────────\n⚠  IMPORTANT — READ BEFORE USE\nThis report was produced by an AI-assisted research/educational tool. It is\nNOT a certified diagnostic device and must not be treated as one.\n\n• All output must be reviewed and confirmed by a licensed radiologist or\n  physician before ANY clinical decision is made.\n• This system must never be deployed to make diagnostic or treatment\n  decisions autonomously. A qualified human must remain in the loop at all\n  times.\n• No real patient-identifying information should be entered, stored, or\n  logged. All test and demonstration data must be de-identified.\n──────────────────────────────────────────────────────────────────────────";

// When DeepSeek is unavailable (no balance -> HTTP 402), run synthesis on Gemini
// instead (the faster triage-tier model). Matches the local runner --no-deepseek.
const NO_DEEPSEEK = ['1', 'true', 'yes'].includes(String($env.XRAY_NO_DEEPSEEK || '').toLowerCase());

const SYNTH_MODEL = $env.DEEPSEEK_SYNTHESIS_MODEL || 'deepseek-v4-pro';
const GEMINI_SYNTH_MODEL = $env.GEMINI_SYNTHESIS_MODEL || $env.GEMINI_TRIAGE_MODEL || 'gemini-2.5-flash';

const SYNTH_PROMPT = `You are the Chief Diagnostician. Three independent specialists have each critiqued the same
radiology report. Your job is NOT to concatenate their opinions — it is to RECONCILE them.

You are given: the original report, and the specialist critique JSON objects that completed.

Do the following:
1. Identify where the specialists AGREE (same finding flagged by 2+ of them).
2. Identify where they DISAGREE, and resolve each disagreement with explicit reasoning
   (whose view is better supported by the report, and why). If it cannot be resolved from the
   available evidence, say so and state what would resolve it.
3. Weigh confidence: down-weight findings only one specialist raised; up-weight consensus findings.
4. Account for missing critiques: if fewer than three critiques are present, lower overall
   confidence and note which perspective is absent.
5. Remember the analysis limitation: text-only agents did not view the image. Reflect this in
   the confidence assessment.
6. Produce a ranked differential and a single most-likely diagnosis (or "no acute abnormality"
   if that is the supported conclusion).
7. Attach the mandatory disclaimer block VERBATIM (provided below) as the "disclaimer" field.

Base everything on the report and the critiques. Do NOT introduce findings none of the inputs
support. Output STRICT JSON matching the final schema. No markdown, no text outside the JSON.

The JSON object MUST have exactly these fields:
{
  "summary": string,
  "primary_findings": string[],
  "points_of_agreement": string[],
  "points_of_disagreement_and_resolution": [ { "point": string, "positions": string[], "resolution": string } ],
  "most_likely_diagnosis": string,
  "differential_diagnoses_ranked": [ { "diagnosis": string, "likelihood": "high"|"moderate"|"low", "supporting_rationale": string } ],
  "confidence_assessment": { "overall_confidence": "low"|"medium"|"high", "rationale": string, "analysis_limitations": string[] },
  "recommended_next_clinical_steps": string[],
  "contributing_specialties": string[],
  "missing_critiques": string[],
  "disclaimer": string   // the mandatory disclaimer, copied VERBATIM
}

MANDATORY DISCLAIMER (copy verbatim into the "disclaimer" field):
${DISCLAIMER}`;

const critiques = ($json.critiques || []).map(c => {
  // Strip internal bookkeeping before showing critiques to the synthesis model.
  const { __backend, __model, __ms, __image_provided, ...clean } = c;
  return { ...clean, backend: __backend, analyzed_image: !!__image_provided };
});

const missing_critiques = ($json.failures || []).map(f =>
  `${f.backend} (${f.specialty || 'specialist'})${f.parse_failed ? ' — returned malformed output' : ''}${f.error ? ` — ${f.error}` : ''}`
);

const merged = {
  original_report: $json.original.report_text,
  report_type: $json.original.report_type,
  patient_context: $json.original.patient_context,
  critiques,
  missing_critiques,
};

// Build the request for whichever synthesis backend is active. The Synthesis
// HTTP node reads synthesis_url / synthesis_auth_name / synthesis_auth_value /
// synthesis_request_body from here, so switching backends needs no node edits.
let synthesis_request_body, synthesis_url, synthesis_auth_name, synthesis_auth_value, synthesis_backend;

if (NO_DEEPSEEK) {
  synthesis_backend = 'gemini';
  synthesis_url = `https://generativelanguage.googleapis.com/v1beta/models/${GEMINI_SYNTH_MODEL}:generateContent`;
  synthesis_auth_name = 'x-goog-api-key';
  synthesis_auth_value = $env.GEMINI_API_KEY || '';
  synthesis_request_body = {
    systemInstruction: { parts: [{ text: SYNTH_PROMPT }] },
    contents: [{ role: 'user', parts: [{ text: JSON.stringify(merged) }] }],
    generationConfig: { temperature: 0.2, responseMimeType: 'application/json' },
  };
} else {
  synthesis_backend = 'deepseek';
  synthesis_url = 'https://api.deepseek.com/chat/completions';
  synthesis_auth_name = 'Authorization';
  synthesis_auth_value = `Bearer ${$env.DEEPSEEK_API_KEY || ''}`;
  synthesis_request_body = {
    model: SYNTH_MODEL,
    messages: [
      { role: 'system', content: SYNTH_PROMPT },
      { role: 'user', content: JSON.stringify(merged) },
    ],
    response_format: { type: 'json_object' },
    reasoning_effort: 'high',
    thinking: { type: 'enabled' },
  };
}

return [{
  json: {
    has_critiques: critiques.length > 0,
    synthesis_request_body,
    synthesis_url,
    synthesis_auth_name,
    synthesis_auth_value,
    synthesis_backend,
    merged,
    original: $json.original,
    failures: $json.failures || [],
    __t_start: $json.__t_start,
    __t_triage_ms: $json.__t_triage_ms,
    __t_fanout_ms: $json.__t_fanout_ms,
    __agent_timings: $json.__agent_timings,
  },
}];

// Node 8 — Parse & Validate Final
// Extracts choices[0].message.content, validates against FinalDiagnosticReport,
// re-inserts the Section 6 disclaimer VERBATIM (hard requirement), strips any
// reasoning_content, and — per Section 2.6 — if synthesis failed after its
// retry, returns the raw critiques plus an explicit "synthesis unavailable"
// notice. The disclaimer is never dropped.

const DISCLAIMER = "──────────────────────────────────────────────────────────────────────────\n⚠  IMPORTANT — READ BEFORE USE\nThis report was produced by an AI-assisted research/educational tool. It is\nNOT a certified diagnostic device and must not be treated as one.\n\n• All output must be reviewed and confirmed by a licensed radiologist or\n  physician before ANY clinical decision is made.\n• This system must never be deployed to make diagnostic or treatment\n  decisions autonomously. A qualified human must remain in the loop at all\n  times.\n• No real patient-identifying information should be entered, stored, or\n  logged. All test and demonstration data must be de-identified.\n──────────────────────────────────────────────────────────────────────────";

const mg = $('Merge Guard').first().json;
const resp = $json;

function extractJson(raw) {
  if (raw == null) return null;
  let s = String(raw).trim().replace(/^```(?:json)?\s*/i, '').replace(/```\s*$/, '');
  const start = s.indexOf('{');
  const end = s.lastIndexOf('}');
  if (start === -1 || end <= start) return null;
  try { return JSON.parse(s.slice(start, end + 1)); } catch (e) { return null; }
}

const strArr = v => (Array.isArray(v) ? v.filter(x => typeof x === 'string') : []);

let final = null;
let synthesis_unavailable = false;
let synthesis_error = '';

if (resp.error) {
  // HTTP node was set to continue-on-fail; the error object lands here after
  // its built-in retry was exhausted.
  synthesis_unavailable = true;
  synthesis_error = String(resp.error.message || resp.error).slice(0, 500);
} else {
  // Accept both response shapes: DeepSeek/OpenAI (choices[].message.content) and
  // Gemini (candidates[].content.parts[].text), so either synthesis backend works.
  const content = resp.choices?.[0]?.message?.content
    ?? resp.candidates?.[0]?.content?.parts?.map(p => p.text || '').join('')
    ?? '';
  final = extractJson(content);
  if (!final) {
    synthesis_unavailable = true;
    synthesis_error = 'synthesis model returned malformed JSON';
  }
}

const contributing = (mg.merged.critiques || []).map(c => `${c.specialty_role} (${c.backend})`);

if (synthesis_unavailable) {
  // Fallback report: raw critiques + explicit notice, disclaimer attached.
  final = {
    summary: 'SYNTHESIS UNAVAILABLE — the reconciliation step failed after retry. The raw, ' +
      'unreconciled specialist critiques are attached below. No synthesized conclusion is offered.',
    primary_findings: (mg.merged.critiques || []).flatMap(c =>
      strArr(c.key_observations).map(o => `[${c.specialty_role}] ${o}`)),
    points_of_agreement: [],
    points_of_disagreement_and_resolution: [],
    most_likely_diagnosis: 'Not determined — synthesis unavailable.',
    differential_diagnoses_ranked: [],
    confidence_assessment: {
      overall_confidence: 'low',
      rationale: `The synthesis backend failed (${synthesis_error}); individual critiques were not reconciled.`,
      analysis_limitations: [],
    },
    recommended_next_clinical_steps: [
      'Have a licensed radiologist or physician review the original report and the raw critiques directly.',
    ],
    contributing_specialties: contributing,
    missing_critiques: mg.merged.missing_critiques || [],
    disclaimer: DISCLAIMER,
    raw_critiques: mg.merged.critiques,
  };
}

// ---- Shape enforcement (FinalDiagnosticReport schema) -----------------------
final.summary = typeof final.summary === 'string' ? final.summary : '';
final.primary_findings = strArr(final.primary_findings);
final.points_of_agreement = strArr(final.points_of_agreement);
final.points_of_disagreement_and_resolution =
  (Array.isArray(final.points_of_disagreement_and_resolution) ? final.points_of_disagreement_and_resolution : [])
    .filter(d => d && typeof d === 'object')
    .map(d => ({
      point: String(d.point || ''),
      positions: strArr(d.positions),
      resolution: String(d.resolution || ''),
    }));
final.most_likely_diagnosis = typeof final.most_likely_diagnosis === 'string'
  ? final.most_likely_diagnosis : 'Not determined.';
final.differential_diagnoses_ranked =
  (Array.isArray(final.differential_diagnoses_ranked) ? final.differential_diagnoses_ranked : [])
    .filter(d => d && typeof d === 'object')
    .map(d => ({
      diagnosis: String(d.diagnosis || ''),
      likelihood: ['high', 'moderate', 'low'].includes(d.likelihood) ? d.likelihood : 'low',
      supporting_rationale: String(d.supporting_rationale || ''),
    }));

const ca = (final.confidence_assessment && typeof final.confidence_assessment === 'object')
  ? final.confidence_assessment : {};
final.confidence_assessment = {
  overall_confidence: ['low', 'medium', 'high'].includes(ca.overall_confidence) ? ca.overall_confidence : 'low',
  rationale: String(ca.rationale || ''),
  analysis_limitations: strArr(ca.analysis_limitations),
};

// Honest-limitations guarantee (Section 6): these two disclosures must always
// be present, whether or not the model included them.
const lims = final.confidence_assessment.analysis_limitations;
const textOnlyCount = (mg.merged.critiques || []).filter(c => !c.analyzed_image).length;
const imgNote = mg.original.image_provided
  ? `${textOnlyCount} of ${(mg.merged.critiques || []).length} completed specialist agents analyzed the report text only, not the image.`
  : 'No image was provided; all agents analyzed the report text only.';
if (!lims.some(l => /text[- ]only|report text only|not the image|no image/i.test(l))) lims.push(imgNote);
if (!lims.some(l => /FDA|CE[- ]cleared|not.*(certified|cleared)/i.test(l))) {
  lims.push('This tool is a research/educational prototype and is not FDA/CE-cleared.');
}

final.recommended_next_clinical_steps = strArr(final.recommended_next_clinical_steps);
final.contributing_specialties = strArr(final.contributing_specialties);
if (final.contributing_specialties.length === 0) final.contributing_specialties = contributing;
final.missing_critiques = strArr(final.missing_critiques);
for (const m of (mg.merged.missing_critiques || [])) {
  if (!final.missing_critiques.includes(m)) final.missing_critiques.push(m);
}

// Hard requirement: disclaimer present and VERBATIM — overwrite unconditionally.
final.disclaimer = DISCLAIMER;

// Never persist or echo the model's thinking trace.
delete final.reasoning_content;

return [{
  json: {
    final_report: final,
    error_report: false,
    synthesis_unavailable,
    synthesis_error,
    original: mg.original,
    __t_start: mg.__t_start,
    __t_triage_ms: mg.__t_triage_ms,
    __t_fanout_ms: mg.__t_fanout_ms,
    __t_synthesis_ms: Date.now() - (mg.__t_start + (mg.__t_triage_ms || 0) + (mg.__t_fanout_ms || 0)),
    __agent_timings: mg.__agent_timings,
    __synthesis_usage: resp.usage || resp.usageMetadata || null,
  },
}];

// Node — Error Report (zero valid critiques)
// Mandated by Section 2.6: never fabricate a diagnosis. Returns an explicit
// "analysis could not be completed" report with the disclaimer still attached.

const DISCLAIMER = "──────────────────────────────────────────────────────────────────────────\n⚠  IMPORTANT — READ BEFORE USE\nThis report was produced by an AI-assisted research/educational tool. It is\nNOT a certified diagnostic device and must not be treated as one.\n\n• All output must be reviewed and confirmed by a licensed radiologist or\n  physician before ANY clinical decision is made.\n• This system must never be deployed to make diagnostic or treatment\n  decisions autonomously. A qualified human must remain in the loop at all\n  times.\n• No real patient-identifying information should be entered, stored, or\n  logged. All test and demonstration data must be de-identified.\n──────────────────────────────────────────────────────────────────────────";

const failures = $json.failures || [];

const final_report = {
  summary: 'Analysis could not be completed — no specialist critiques were produced. ' +
    'All three specialist backends failed or returned unusable output. No diagnostic ' +
    'conclusion is offered.',
  primary_findings: [],
  points_of_agreement: [],
  points_of_disagreement_and_resolution: [],
  most_likely_diagnosis: 'Not determined — analysis could not be completed.',
  differential_diagnoses_ranked: [],
  confidence_assessment: {
    overall_confidence: 'low',
    rationale: 'No specialist critique completed; there is no basis for any conclusion.',
    analysis_limitations: [
      'Zero of three specialist agents produced a valid critique.',
      'This tool is a research/educational prototype and is not FDA/CE-cleared.',
    ],
  },
  recommended_next_clinical_steps: [
    'Have the original report reviewed directly by a licensed radiologist or physician.',
    'Retry the analysis once backend availability is restored.',
  ],
  contributing_specialties: [],
  missing_critiques: failures.map(f =>
    `${f.backend} (${f.specialty || 'specialist'})${f.parse_failed ? ' — returned malformed output' : ''}${f.error ? ` — ${f.error}` : ''}`
  ),
  disclaimer: DISCLAIMER,
};

return [{
  json: {
    final_report,
    error_report: true,
    synthesis_unavailable: false,
    original: $json.original,
    __t_start: $json.__t_start,
    __t_triage_ms: $json.__t_triage_ms,
    __t_fanout_ms: $json.__t_fanout_ms,
    __t_synthesis_ms: 0,
    __agent_timings: $json.__agent_timings,
  },
}];

// Node 9 — Render Report
// Renders the FinalDiagnosticReport JSON to markdown in the Section 7 layout
// order, with the disclaimer as a visually distinct block at BOTH top and
// bottom. HTML/PDF renderers can be added behind config flags (see README).

const r = $json.final_report;

const lines = [];
const section = (title) => { lines.push(''); lines.push(`## ${title}`); lines.push(''); };
const bullets = (arr, empty) => {
  if (!arr || arr.length === 0) { lines.push(`_${empty}_`); return; }
  for (const x of arr) lines.push(`- ${x}`);
};
const disclaimerBlock = () => {
  lines.push('```text');
  lines.push(r.disclaimer);
  lines.push('```');
};

lines.push('# AI-Assisted X-Ray Report Analysis (Research Prototype)');
lines.push('');
disclaimerBlock();

section('Summary');
lines.push(r.summary || '_No summary produced._');

section('Primary Findings');
bullets(r.primary_findings, 'None reported.');

section('Points of Agreement');
bullets(r.points_of_agreement, 'None identified.');

section('Points of Disagreement & Resolution');
if (!r.points_of_disagreement_and_resolution || r.points_of_disagreement_and_resolution.length === 0) {
  lines.push('_No disagreements between specialists._');
} else {
  for (const d of r.points_of_disagreement_and_resolution) {
    lines.push(`- **Point:** ${d.point}`);
    for (const p of (d.positions || [])) lines.push(`  - Position: ${p}`);
    lines.push(`  - **Resolution:** ${d.resolution}`);
  }
}

section('Most Likely Diagnosis');
lines.push(`**${r.most_likely_diagnosis}**`);

section('Differential Diagnoses (Ranked)');
if (!r.differential_diagnoses_ranked || r.differential_diagnoses_ranked.length === 0) {
  lines.push('_None offered._');
} else {
  lines.push('| # | Diagnosis | Likelihood | Supporting rationale |');
  lines.push('|---|-----------|------------|----------------------|');
  r.differential_diagnoses_ranked.forEach((d, i) => {
    const esc = s => String(s || '').replace(/\|/g, '\\|').replace(/\n/g, ' ');
    lines.push(`| ${i + 1} | ${esc(d.diagnosis)} | ${d.likelihood} | ${esc(d.supporting_rationale)} |`);
  });
}

section('Confidence Assessment');
lines.push(`**Overall confidence:** ${r.confidence_assessment.overall_confidence}`);
lines.push('');
lines.push(r.confidence_assessment.rationale || '');
lines.push('');
lines.push('**Analysis limitations:**');
bullets(r.confidence_assessment.analysis_limitations, 'None stated.');

section('Recommended Next Clinical Steps');
bullets(r.recommended_next_clinical_steps, 'None offered.');

section('Contributing Specialties');
bullets(r.contributing_specialties, 'None — no critiques completed.');
if (r.missing_critiques && r.missing_critiques.length > 0) {
  lines.push('');
  lines.push('**Missing critiques (failed or timed out):**');
  bullets(r.missing_critiques, '');
}

if ($json.synthesis_unavailable && r.raw_critiques) {
  section('Raw Specialist Critiques (synthesis unavailable)');
  lines.push('```json');
  lines.push(JSON.stringify(r.raw_critiques, null, 2));
  lines.push('```');
}

lines.push('');
lines.push('---');
lines.push('');
disclaimerBlock();

// ---- HTML rendering (for the Form completion page, respondWith=showText) ----
const esc = (s) => String(s == null ? '' : s)
  .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
const h = [];
const ul = (arr, empty) => {
  if (!arr || arr.length === 0) { h.push(`<p class="muted">${empty}</p>`); return; }
  h.push('<ul>' + arr.map(x => `<li>${esc(x)}</li>`).join('') + '</ul>');
};
const disclaimerHtml = () =>
  `<pre class="disclaimer">${esc(r.disclaimer)}</pre>`;

h.push(`<style>
  .xray{max-width:820px;margin:0 auto;padding:24px;font-family:-apple-system,Segoe UI,Roboto,sans-serif;line-height:1.5;color:#1a1a1a}
  .xray h1{font-size:1.5rem} .xray h2{font-size:1.1rem;margin-top:1.6rem;border-bottom:1px solid #e5e5e5;padding-bottom:4px}
  .xray pre.disclaimer{background:#fff7d6;border:2px solid #e0b500;border-radius:8px;padding:14px;white-space:pre-wrap;font-family:ui-monospace,monospace;font-size:.82rem}
  .xray table{border-collapse:collapse;width:100%;font-size:.9rem} .xray th,.xray td{border:1px solid #ddd;padding:6px 8px;text-align:left;vertical-align:top}
  .xray .muted{color:#888;font-style:italic} .xray .diag{font-size:1.15rem;font-weight:600;color:#0b5}
  .xray .conf{display:inline-block;padding:2px 10px;border-radius:12px;background:#eef;font-weight:600}
</style>`);
h.push('<div class="xray">');
h.push('<h1>AI-Assisted X-Ray Report Analysis <span class="muted">(Research Prototype)</span></h1>');
h.push(disclaimerHtml());
h.push('<h2>Summary</h2>'); h.push(`<p>${esc(r.summary) || '<span class="muted">No summary produced.</span>'}</p>`);
h.push('<h2>Primary Findings</h2>'); ul(r.primary_findings, 'None reported.');
h.push('<h2>Points of Agreement</h2>'); ul(r.points_of_agreement, 'None identified.');
h.push('<h2>Points of Disagreement &amp; Resolution</h2>');
if (!r.points_of_disagreement_and_resolution || r.points_of_disagreement_and_resolution.length === 0) {
  h.push('<p class="muted">No disagreements between specialists.</p>');
} else {
  for (const d of r.points_of_disagreement_and_resolution) {
    h.push(`<p><strong>${esc(d.point)}</strong></p><ul>` +
      (d.positions || []).map(p => `<li>${esc(p)}</li>`).join('') +
      `</ul><p><em>Resolution:</em> ${esc(d.resolution)}</p>`);
  }
}
h.push('<h2>Most Likely Diagnosis</h2>'); h.push(`<p class="diag">${esc(r.most_likely_diagnosis)}</p>`);
h.push('<h2>Differential Diagnoses (Ranked)</h2>');
if (!r.differential_diagnoses_ranked || r.differential_diagnoses_ranked.length === 0) {
  h.push('<p class="muted">None offered.</p>');
} else {
  h.push('<table><tr><th>#</th><th>Diagnosis</th><th>Likelihood</th><th>Rationale</th></tr>' +
    r.differential_diagnoses_ranked.map((d, i) =>
      `<tr><td>${i + 1}</td><td>${esc(d.diagnosis)}</td><td>${esc(d.likelihood)}</td><td>${esc(d.supporting_rationale)}</td></tr>`).join('') +
    '</table>');
}
h.push('<h2>Confidence Assessment</h2>');
h.push(`<p><span class="conf">${esc(r.confidence_assessment.overall_confidence)}</span></p>`);
h.push(`<p>${esc(r.confidence_assessment.rationale)}</p>`);
h.push('<p><strong>Analysis limitations:</strong></p>'); ul(r.confidence_assessment.analysis_limitations, 'None stated.');
h.push('<h2>Recommended Next Clinical Steps</h2>'); ul(r.recommended_next_clinical_steps, 'None offered.');
h.push('<h2>Contributing Specialties</h2>'); ul(r.contributing_specialties, 'None — no critiques completed.');
if (r.missing_critiques && r.missing_critiques.length > 0) {
  h.push('<p><strong>Missing critiques (failed or timed out):</strong></p>'); ul(r.missing_critiques, '');
}
h.push('<hr>'); h.push(disclaimerHtml());
h.push('</div>');
const html = h.join('\n');

return [{
  json: {
    markdown: lines.join('\n'),
    html,
    final_report: r,
    error_report: $json.error_report,
    synthesis_unavailable: $json.synthesis_unavailable,
    synthesis_error: $json.synthesis_error || '',
    original: $json.original,
    __t_start: $json.__t_start,
    __t_triage_ms: $json.__t_triage_ms,
    __t_fanout_ms: $json.__t_fanout_ms,
    __t_synthesis_ms: $json.__t_synthesis_ms,
    __agent_timings: $json.__agent_timings,
    __synthesis_usage: $json.__synthesis_usage || null,
  },
}];

// Node 10 — Audit Log
// Appends a redacted, PHI-free record per run to <XRAY_OUT_DIR>/audit.jsonl and
// saves the rendered (already de-identified) report next to it.
//
// Retained: timings, model IDs, token counts, error/parse flags, redacted output.
// NEVER retained: raw uploaded files, image bytes, reasoning_content, identifiers.
//
// Requires the n8n process env var: NODE_FUNCTION_ALLOW_BUILTIN=fs,path
// (see README). Logging must never break the pipeline: all failures here are
// swallowed after a console warning.

function redactPHI(text) {
  if (!text) return text;
  let t = String(text);
  const rules = [
    [/\b(patient(?:\s+name)?|name|pt\.?)\s*[:\-]\s*[A-Z][A-Za-z'\-]+(?:[ ,]+[A-Z][A-Za-z'\-]+)*/g, '$1: [REDACTED]'],
    [/\b(dob|date\s+of\s+birth|birth\s*date)\s*[:\-]?\s*\d{1,4}[\/\-.]\d{1,2}[\/\-.]\d{1,4}/gi, '$1: [REDACTED]'],
    [/\b(mrn|medical\s+record\s+(?:no\.?|number|#)|record\s*#)\s*[:\-]?\s*[A-Za-z0-9\-]+/gi, '$1: [REDACTED]'],
    [/\b(accession\s*(?:no\.?|number|#)?)\s*[:\-]\s*[A-Za-z0-9\-]+/gi, '$1: [REDACTED]'],
    [/\b(ssn|social\s+security(?:\s+number)?)\s*[:\-]?\s*\d{3}-?\d{2}-?\d{4}/gi, '$1: [REDACTED]'],
    [/\b\d{3}[\-. ]\d{3}[\-. ]\d{4}\b/g, '[REDACTED-PHONE]'],
    [/\b[\w.+-]+@[\w-]+\.[\w.-]+\b/g, '[REDACTED-EMAIL]'],
  ];
  for (const [re, rep] of rules) t = t.replace(re, rep);
  return t;
}

const j = $json;

const record = {
  timestamp: new Date().toISOString(),
  execution_id: $execution.id,
  report_type: j.original ? j.original.report_type : null,
  triage_ms: j.__t_triage_ms || null,
  fanout_ms: j.__t_fanout_ms || null,
  synthesis_ms: j.__t_synthesis_ms || null,
  total_ms: j.__t_start ? Date.now() - j.__t_start : null,
  agents: j.__agent_timings || [],
  synthesis_usage: j.__synthesis_usage
    ? { prompt_tokens: j.__synthesis_usage.prompt_tokens, completion_tokens: j.__synthesis_usage.completion_tokens }
    : null,
  error_report: !!j.error_report,
  synthesis_unavailable: !!j.synthesis_unavailable,
  synthesis_error: j.synthesis_error || null,
  missing_critiques: (j.final_report && j.final_report.missing_critiques) || [],
  overall_confidence: j.final_report ? j.final_report.confidence_assessment.overall_confidence : null,
  most_likely_diagnosis: j.final_report ? redactPHI(j.final_report.most_likely_diagnosis) : null,
  summary_redacted: j.final_report ? redactPHI(j.final_report.summary) : null,
  // Evaluation-plan fields (Section 5.3/5.4) — filled in manually per test run.
  eval: { agreement_rate: null, hallucinations: null, rubric: { plausibility: null, consistency: null, clarity: null } },
};

try {
  const fs = require('fs');
  const path = require('path');
  const outDir = $env.XRAY_OUT_DIR || '/data/xray-agent/out';
  fs.mkdirSync(outDir, { recursive: true });
  fs.appendFileSync(path.join(outDir, 'audit.jsonl'), JSON.stringify(record) + '\n', 'utf8');
  const stamp = record.timestamp.replace(/[:.]/g, '-');
  fs.writeFileSync(path.join(outDir, `report-${stamp}-${$execution.id}.md`), redactPHI(j.markdown), 'utf8');
  if (j.html) fs.writeFileSync(path.join(outDir, `report-${stamp}-${$execution.id}.html`), redactPHI(j.html), 'utf8');
} catch (e) {
  // Never fail the pipeline because of logging. Most likely cause:
  // NODE_FUNCTION_ALLOW_BUILTIN=fs,path not set, or XRAY_OUT_DIR not writable.
  console.log('AUDIT LOG WRITE FAILED (pipeline continues): ' + String(e && e.message ? e.message : e));
}

// Forward the full item so the Form completion node still has `html` to render
// (dropping it here left the completion page blank).
return [{ json: { ...j } }];
